import React, { useState } from 'react';
import {
  Box,
  Typography,
  Paper,
  Button,
  Table,
  TableBody,
  TableCell,
  TableContainer,
  TableHead,
  TableRow,
  IconButton,
  Chip,
  useTheme,
  Card,
  CardContent,
  Dialog,
  DialogTitle,
  DialogContent,
  DialogActions,
  TextField,
  FormControl,
  InputLabel,
  Select,
  MenuItem,
  Divider,
  Tabs,
  Tab,
  SelectChangeEvent
} from '@mui/material';
import { 
  Add, 
  Edit, 
  Delete, 
  MoreVert, 
  Visibility, 
  CarRental, 
  People, 
  MonetizationOn,
  CardGiftcard,
  Settings
} from '@mui/icons-material';
import { styled, alpha } from '@mui/material/styles';
import { motion } from 'framer-motion';
import { useFirebase } from '../context/FirebaseContext';
import { addDoc, updateDoc, deleteDoc, doc, collection } from 'firebase/firestore';
import { db } from '../firebase/config';

const AdminHeader = styled(Paper)(({ theme }) => ({
  padding: theme.spacing(3),
  borderRadius: theme.spacing(2),
  display: 'flex',
  justifyContent: 'space-between',
  alignItems: 'center',
  marginBottom: theme.spacing(3),
  background: 'linear-gradient(90deg, #2196F3 0%, #1976D2 100%)',
  color: 'white',
  boxShadow: '0 4px 20px rgba(0,0,0,0.1)',
}));

const StatsCard = styled(Card)(({ theme }) => ({
  borderRadius: theme.spacing(2),
  boxShadow: '0 4px 12px rgba(0,0,0,0.05)',
  height: '100%',
  transition: 'transform 0.2s ease, box-shadow 0.2s ease',
  '&:hover': {
    transform: 'translateY(-5px)',
    boxShadow: '0 8px 24px rgba(0,0,0,0.1)',
  },
}));

const StatsIcon = styled(Box)(({ theme }) => ({
  display: 'flex',
  alignItems: 'center',
  justifyContent: 'center',
  width: 60,
  height: 60,
  borderRadius: '50%',
  marginBottom: theme.spacing(2),
  backgroundColor: alpha(theme.palette.primary.main, 0.1),
  color: theme.palette.primary.main,
}));

const TablePaper = styled(Paper)(({ theme }) => ({
  borderRadius: theme.spacing(2),
  overflow: 'hidden',
  boxShadow: '0 4px 12px rgba(0,0,0,0.05)',
  marginBottom: theme.spacing(4),
}));

// Исправленный интерфейс Raffle (без carModel)
interface Raffle {
  id: string;
  title: string;
  image: string;
  description: string;
  ticketsSold: number;
  totalTickets: number;
  price: number;
  year: number;
  participants: number;
  endDate: string;
  companyId: string;
  status: 'active' | 'completed' | 'draft';
}

// Компонент для панели с разными вкладками
const TabPanel = (props: { children?: React.ReactNode; index: number; value: number }) => {
  const { children, value, index, ...other } = props;

  return (
    <div
      role="tabpanel"
      hidden={value !== index}
      id={`admin-tabpanel-${index}`}
      aria-labelledby={`admin-tab-${index}`}
      style={{ padding: '16px 0' }}
      {...other}
    >
      {value === index && children}
    </div>
  );
};

// Создаем компоненты-обертки для замены Grid
const GridContainer = ({ children, spacing = 0, ...props }) => (
  <Box 
    sx={{ 
      display: 'flex', 
      flexWrap: 'wrap', 
      margin: `-${spacing * 4}px`,
      width: 'calc(100% + ${spacing * 8}px)',
      ...props.sx
    }}
    {...props}
  >
    {children}
  </Box>
);

const GridItem = ({ children, xs, md, ...props }) => {
  let width = '100%';
  if (md) {
    width = {
      xs: xs === 12 ? '100%' : `${(xs / 12) * 100}%`,
      md: `${(md / 12) * 100}%`
    };
  } else if (xs) {
    width = `${(xs / 12) * 100}%`;
  }
  
  return (
    <Box 
      sx={{ 
        padding: 2,
        boxSizing: 'border-box',
        flexShrink: 0,
        width,
        ...props.sx
      }}
      {...props}
    >
      {children}
    </Box>
  );
};

const AdminPage: React.FC = () => {
  const theme = useTheme();
  const { raffles, companies, refreshData } = useFirebase();
  const [tabValue, setTabValue] = useState(0);
  const [openDialog, setOpenDialog] = useState(false);
  const [editRaffle, setEditRaffle] = useState<any | null>(null);
  const [form, setForm] = useState<any>({
    title: '',
    image: '',
    description: '',
    totalTickets: '',
    ticketsSold: 0,
    price: '',
    status: 'draft',
    endDate: '',
    companyId: '',
    year: '',
    participants: 0
  });
  
  // Данные статистики
  const statsData = [
    { 
      title: 'Всего розыгрышей', 
      value: 12, 
      icon: <CardGiftcard sx={{ fontSize: 30 }} />,
      change: '+2 за месяц'
    },
    { 
      title: 'Активных участников', 
      value: 1258, 
      icon: <People sx={{ fontSize: 30 }} />,
      change: '+125 за месяц'
    },
    { 
      title: 'Продано билетов', 
      value: 5780, 
      icon: <MonetizationOn sx={{ fontSize: 30 }} />,
      change: '+450 за месяц'
    },
  ];
  
  const handleTabChange = (_event: React.SyntheticEvent, newValue: number) => {
    setTabValue(newValue);
  };
  
  // Открыть диалог создания/редактирования
  const handleOpenDialog = (raffle?: any) => {
    if (raffle) {
      setEditRaffle(raffle);
      setForm({ ...raffle });
    } else {
      setEditRaffle(null);
      setForm({
        title: '', image: '', description: '', totalTickets: '', ticketsSold: 0, price: '', status: 'draft', endDate: '', companyId: '', year: '', participants: 0
      });
    }
    setOpenDialog(true);
  };
  
  // Закрыть диалог
  const handleCloseDialog = () => {
    setOpenDialog(false);
    setEditRaffle(null);
  };

  // Обработка изменения формы
  const handleFormChange = (e: React.ChangeEvent<HTMLInputElement | { name?: string; value: unknown }>) => {
    const { name, value } = e.target;
    setForm((prev: any) => ({ ...prev, [name as string]: value }));
  };

  // Обработка изменения формы для Select
  const handleSelectChange = (e: SelectChangeEvent) => {
    const { name, value } = e.target;
    setForm((prev: any) => ({ ...prev, [name as string]: value }));
  };

  // Сохранить розыгрыш (создать или обновить)
  const handleSaveRaffle = async () => {
    if (editRaffle) {
      // Обновление
      await updateDoc(doc(db, 'raffles', editRaffle.id), form);
    } else {
      // Создание
      await addDoc(collection(db, 'raffles'), form);
    }
    await refreshData();
    handleCloseDialog();
  };

  // Удалить розыгрыш
  const handleDeleteRaffle = async (id: string) => {
    await deleteDoc(doc(db, 'raffles', id));
    await refreshData();
  };
  
  const getStatusColor = (status: string) => {
    switch (status) {
      case 'active':
        return 'success';
      case 'completed':
        return 'primary';
      case 'draft':
        return 'default';
      default:
        return 'default';
    }
  };
  
  const getStatusLabel = (status: string) => {
    switch (status) {
      case 'active':
        return 'Активен';
      case 'completed':
        return 'Завершен';
      case 'draft':
        return 'Черновик';
      default:
        return 'Неизвестно';
    }
  };
  
  return (
    <Box sx={{ padding: 2, paddingBottom: 10 }}>
      <motion.div
        initial={{ opacity: 0, y: 20 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ duration: 0.4 }}
      >
        <AdminHeader elevation={0}>
          <Box>
            <Typography variant="h5" sx={{ fontWeight: 700 }}>
              Панель администратора
            </Typography>
            <Typography variant="body2" sx={{ opacity: 0.8, mt: 0.5 }}>
              Управление розыгрышами и настройками
            </Typography>
          </Box>
          <Button 
            variant="contained" 
            startIcon={<Add />}
            onClick={handleOpenDialog}
            sx={{ 
              backgroundColor: 'white', 
              color: 'primary.main',
              '&:hover': {
                backgroundColor: 'rgba(255, 255, 255, 0.8)'
              }
            }}
          >
            Новый розыгрыш
          </Button>
        </AdminHeader>
        
        <Box sx={{ mb: 4 }}>
          <GridContainer spacing={3}>
            {statsData.map((stat, index) => (
              <GridItem xs={12} md={4} key={index}>
                <StatsCard>
                  <CardContent sx={{ p: 3 }}>
                    <StatsIcon>
                      {stat.icon}
                    </StatsIcon>
                    <Typography variant="h4" sx={{ fontWeight: 700, mb: 0.5 }}>
                      {stat.value}
                    </Typography>
                    <Typography variant="body2" color="text.secondary" gutterBottom>
                      {stat.title}
                    </Typography>
                    <Typography variant="caption" color="primary.main" sx={{ fontWeight: 500 }}>
                      {stat.change}
                    </Typography>
                  </CardContent>
                </StatsCard>
              </GridItem>
            ))}
          </GridContainer>
        </Box>
        
        <Tabs 
          value={tabValue} 
          onChange={handleTabChange}
          sx={{
            mb: 3,
            '& .MuiTabs-indicator': {
              height: 3,
              borderRadius: 3,
            },
            '& .MuiTab-root': {
              textTransform: 'none',
              fontWeight: 600,
              fontSize: '0.9rem',
              minWidth: 100,
            },
          }}
        >
          <Tab icon={<CarRental />} label="Розыгрыши" iconPosition="start" />
          <Tab icon={<People />} label="Участники" iconPosition="start" />
          <Tab icon={<Settings />} label="Настройки" iconPosition="start" />
        </Tabs>
        
        <TabPanel value={tabValue} index={0}>
          <TablePaper>
            <Box sx={{ p: 2, display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
              <Typography variant="h6" sx={{ fontWeight: 600 }}>
                Все розыгрыши
              </Typography>
              <Button 
                variant="outlined" 
                startIcon={<Add />}
                size="small"
                onClick={handleOpenDialog}
              >
                Добавить
              </Button>
            </Box>
            <Divider />
            <TableContainer>
              <Table sx={{ minWidth: 650 }}>
                <TableHead>
                  <TableRow>
                    <TableCell>Название</TableCell>
                    <TableCell>Год выпуска</TableCell>
                    <TableCell>Билетов продано</TableCell>
                    <TableCell>Цена (₽)</TableCell>
                    <TableCell>Дата окончания</TableCell>
                    <TableCell>Статус</TableCell>
                    <TableCell>Действия</TableCell>
                  </TableRow>
                </TableHead>
                <TableBody>
                  {raffles.map((raffle) => (
                    <TableRow
                      key={raffle.id}
                      sx={{ '&:last-child td, &:last-child th': { border: 0 } }}
                    >
                      <TableCell component="th" scope="row" sx={{ fontWeight: 500 }}>
                        {raffle.title}
                      </TableCell>
                      <TableCell>{raffle.year}</TableCell>
                      <TableCell>
                        {raffle.ticketsSold} / {raffle.totalTickets}
                        <Box sx={{ width: '100%', mt: 1 }}>
                          <Box 
                            sx={{ 
                              height: 4, 
                              borderRadius: 4, 
                              backgroundColor: 'rgba(33, 150, 243, 0.2)',
                              position: 'relative',
                              overflow: 'hidden',
                            }}
                          >
                            <Box 
                              sx={{ 
                                position: 'absolute',
                                left: 0,
                                top: 0,
                                height: '100%',
                                width: `${(raffle.ticketsSold / raffle.totalTickets) * 100}%`,
                                background: 'linear-gradient(90deg, #2196F3 0%, #1976D2 100%)',
                                borderRadius: 4,
                              }} 
                            />
                          </Box>
                        </Box>
                      </TableCell>
                      <TableCell>{raffle.price}</TableCell>
                      <TableCell>{raffle.endDate}</TableCell>
                      <TableCell>
                        <Chip 
                          label={getStatusLabel(raffle.status)} 
                          color={getStatusColor(raffle.status) as any}
                          size="small"
                        />
                      </TableCell>
                      <TableCell>
                        <Box sx={{ display: 'flex' }}>
                          <IconButton size="small" color="primary" onClick={() => handleOpenDialog(raffle)}><Edit fontSize="small" /></IconButton>
                          <IconButton size="small" color="error" onClick={() => handleDeleteRaffle(raffle.id)}><Delete fontSize="small" /></IconButton>
                        </Box>
                      </TableCell>
                    </TableRow>
                  ))}
                </TableBody>
              </Table>
            </TableContainer>
          </TablePaper>
        </TabPanel>
        
        <TabPanel value={tabValue} index={1}>
          <Paper sx={{ p: 3, borderRadius: 2 }}>
            <Typography variant="h6" sx={{ fontWeight: 600 }}>
              Список участников (скоро будет доступен)
            </Typography>
          </Paper>
        </TabPanel>
        
        <TabPanel value={tabValue} index={2}>
          <Paper sx={{ p: 3, borderRadius: 2 }}>
            <Typography variant="h6" sx={{ fontWeight: 600, mb: 3 }}>
              Настройки приложения
            </Typography>
            <GridContainer spacing={3}>
              <GridItem xs={12} md={6}>
                <TextField 
                  fullWidth 
                  label="Название приложения" 
                  defaultValue="Авторозыгрыш"
                  variant="outlined"
                  margin="normal"
                />
                <TextField 
                  fullWidth 
                  label="Контактный email" 
                  defaultValue="support@autoraffle.ru"
                  variant="outlined"
                  margin="normal"
                />
                <FormControl fullWidth margin="normal">
                  <InputLabel>Тема оформления</InputLabel>
                  <Select defaultValue="light">
                    <MenuItem value="light">Светлая</MenuItem>
                    <MenuItem value="dark">Темная</MenuItem>
                    <MenuItem value="auto">Системная</MenuItem>
                  </Select>
                </FormControl>
              </GridItem>
              <GridItem xs={12} md={6}>
                <FormControl fullWidth margin="normal">
                  <InputLabel>Валюта</InputLabel>
                  <Select defaultValue="rub">
                    <MenuItem value="rub">Рубли (₽)</MenuItem>
                    <MenuItem value="usd">Доллары ($)</MenuItem>
                    <MenuItem value="eur">Евро (€)</MenuItem>
                  </Select>
                </FormControl>
                <TextField 
                  fullWidth 
                  label="Комиссия платежной системы (%)" 
                  defaultValue="2.5"
                  variant="outlined"
                  margin="normal"
                  type="number"
                />
                <Box sx={{ mt: 3 }}>
                  <Button 
                    variant="contained" 
                    color="primary"
                    size="large"
                    sx={{ mr: 2 }}
                  >
                    Сохранить настройки
                  </Button>
                  <Button variant="outlined">
                    Отмена
                  </Button>
                </Box>
              </GridItem>
            </GridContainer>
          </Paper>
        </TabPanel>
      </motion.div>
      
      {/* Диалог для создания нового розыгрыша */}
      <Dialog open={openDialog} onClose={handleCloseDialog} maxWidth="md" fullWidth>
        <DialogTitle>{editRaffle ? 'Редактировать розыгрыш' : 'Создать новый розыгрыш'}</DialogTitle>
        <DialogContent dividers>
          <GridContainer spacing={3}>
            <GridItem xs={12} md={6}>
              <TextField fullWidth margin="normal" label="Название розыгрыша" name="title" value={form.title} onChange={handleFormChange} />
              <TextField fullWidth margin="normal" label="Изображение URL" name="image" value={form.image} onChange={handleFormChange} />
              <TextField fullWidth margin="normal" label="Описание" name="description" value={form.description} onChange={handleFormChange} multiline rows={4} />
              <FormControl fullWidth margin="normal">
                <InputLabel>Партнёр</InputLabel>
                <Select name="companyId" value={form.companyId} onChange={handleSelectChange} label="Партнёр">
                  {companies.map((company) => (
                    <MenuItem key={company.id} value={company.id}>{company.name}</MenuItem>
                  ))}
                </Select>
              </FormControl>
            </GridItem>
            <GridItem xs={12} md={6}>
              <TextField fullWidth margin="normal" label="Год выпуска" name="year" value={form.year} onChange={handleFormChange} />
              <TextField fullWidth margin="normal" label="Количество билетов" name="totalTickets" value={form.totalTickets} onChange={handleFormChange} type="number" />
              <TextField fullWidth margin="normal" label="Продано билетов" name="ticketsSold" value={form.ticketsSold} onChange={handleFormChange} type="number" />
              <TextField fullWidth margin="normal" label="Цена билета" name="price" value={form.price} onChange={handleFormChange} type="number" />
              <TextField fullWidth margin="normal" label="Дата окончания" name="endDate" value={form.endDate} onChange={handleFormChange} type="date" InputLabelProps={{ shrink: true }} />
              <FormControl fullWidth margin="normal">
                <InputLabel>Статус розыгрыша</InputLabel>
                <Select name="status" value={form.status} onChange={handleSelectChange} label="Статус розыгрыша">
                  <MenuItem value="active">Активный</MenuItem>
                  <MenuItem value="draft">Черновик</MenuItem>
                  <MenuItem value="completed">Завершён</MenuItem>
                </Select>
              </FormControl>
            </GridItem>
          </GridContainer>
        </DialogContent>
        <DialogActions>
          <Button onClick={handleCloseDialog} color="inherit">Отмена</Button>
          <Button variant="contained" color="primary" onClick={handleSaveRaffle}>{editRaffle ? 'Сохранить' : 'Создать'}</Button>
        </DialogActions>
      </Dialog>
    </Box>
  );
};

export default AdminPage;
